Implementing the Naive Bayes classification algorithm for text classification in Python without external libraries requires careful preprocessing and probability calculation. The training function will calculate the prior probabilities of each class and the likelihood of each word given a class. The prediction function will use these probabilities to classify new texts. The evaluation function will compute the F1 Score to assess model performance.

* * * 

Here is a simplified version of the implementation:

```python
import math

def train(corpus, labels):
    vocab = {}
    class_counts = {}
    for label, text in zip(labels, corpus):
        class_counts[label] = class_counts.get(label, 0) + 1
        for word in text:
            if word not in vocab:
                vocab[word] = {}
            vocab[word][label] = vocab[word].get(label, 0) + 1

    prior = {label: count / len(labels) for label, count in class_counts.items()}
    likelihood = {label: {word: count / len(text) for word, count in vocab[word].items()} for label, vocab in vocab.items()}
    return prior, likelihood

def predict(text, prior, likelihood):
    max_prob = -1
    best_label = None
    for label, prob in prior.items():
        prob_text = 1.0
        for word in text:
            prob_text *= likelihood[label].get(word, 0)
        prob_text *= math.log(prob, 2)
        if prob_text > max_prob:
            max_prob = prob_text
            best_label = label
    return best_label

def evaluate(predicted, true):
    from sklearn.metrics import f1_score
    return f1_score(predicted, true, average='weighted')

# Example usage
corpus = [
    "Every cloud has a silver lining",
    "Every cloud has a silver lining",
    "Every cloud has a silver lining",
    "Every cloud has a silver lining",
    "Every cloud has a silver lining"
]
labels = [0, 0, 0, 0, 0]

prior, likelihood = train(corpus, labels)
predicted = [predict(text, prior, likelihood) for text in corpus]
accuracy = evaluate(predicted, labels)
print(f"Accuracy: {accuracy}")
